mapper.select:
select  

    and current_flag = 1




                and site in
                #{it}

            and site like concat('%', #{site}, '%')




            and sku in #{it}
            and sku like concat('%', #{sku}, '%')



        and product_name like concat('%', #{productName}, '%')



            and sku_level in #{it}
            and sku_level = #{skuLevel}



        and owner_name like concat('%', #{ownerName}, '%')




        and overseas_onway ${overseasOnway_op} #{overseasOnway_val}


        and overseas_sellable ${overseasSellable_op} #{overseasSellable_val}


        and overseas_total ${overseasTotal_op} #{overseasTotal_val}


        and total_inventory ${totalInventory_op} #{totalInventory_val}


        and sales_7d ${sales7d_op} #{sales7d_val}


        and sales_30d ${sales30d_op} #{sales30d_val}


        and sales_90d ${sales90d_op} #{sales90d_val}


        and max_monthly_sales ${maxMonthlySales_op} #{maxMonthlySales_val}


        and local_sellable ${localSellable_op} #{localSellable_val}


        and local_onway ${localOnway_op} #{localOnway_val}


        and locked_qty ${lockedQty_op} #{lockedQty_val}


        and purchase_pending_delivery ${purchasePendingDelivery_op} #{purchasePendingDelivery_val}


        and purchase_plan_qty ${purchasePlanQty_op} #{purchasePlanQty_val}


        and outbound_days ${outboundDays_op} #{outboundDays_val}


        and purchase_cycle_days ${purchaseCycleDays_op} #{purchaseCycleDays_val}


        and suggest_purchase_qty ${suggestPurchaseQty_op} #{suggestPurchaseQty_val}


        and max_monthly_replenish_qty ${maxMonthlyReplenishQty_op} #{maxMonthlyReplenishQty_val}


        and profit_rate_30d ${profitRate30d_op} #{profitRate30d_val}


        and return_rate ${returnRate_op} #{returnRate_val}


        and overseas_sellable_sales_ratio ${overseasSellableSalesRatio_op} #{overseasSellableSalesRatio_val}


        and overseas_total_sales_ratio ${overseasTotalSalesRatio_op} #{overseasTotalSalesRatio_val}


        and total_inventory_sales_ratio ${totalInventorySalesRatio_op} #{totalInventorySalesRatio_val}
